<script setup>import {computed,ref} from 'vue';import {courses} from '../courses';import CourseCard from '../components/CourseCard.vue';const searchTerm=ref('');const filteredCourses=computed(()=>courses.filter(c=>c.name.toLowerCase().includes(searchTerm.value.toLowerCase())));</script><template><main><h1>Courses</h1><label>Search courses <input v-model="searchTerm"></label><section class="grid"><CourseCard v-for="course in filteredCourses" :key="course.id" :course="course"/></section></main></template>
